// Home.jsx
import React from "react";
import "./Home.css";

export default function Home() {
  return (
    <div className="home-wrapper" style={{ padding: 40, textAlign: "center" }}>
      <img src="/prasa-logo.png" alt="PRASA" style={{ width: 140, marginBottom: 20 }} />
      <h2>PRASA Infocom & Power Solutions Pvt. Ltd.</h2>
      <p>Welcome to the Employee Portal</p>

      <div style={{ marginTop: 40, display: "flex", justifyContent: "center", gap: 20 }}>
        <a href="/profile" className="home-btn">Profile</a>
        <a href="/settings" className="home-btn">Settings</a>
      </div>
    </div>
  );
}
